class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right
def build_tree_pre_in(preorder, inorder) -> TreeNode:
    if not preorder or not inorder:
        return None
    pos = {}
    for i, v in enumerate(inorder):
        pos[v] = i
    pre_i = 0
    def build(l, r):
        nonlocal pre_i
        if l > r:
            return None
        val = preorder[pre_i]
        pre_i += 1
        root = TreeNode(val)
        m = pos[val]
        root.left = build(l, m - 1)
        root.right = build(m + 1, r)
        return root
    return build(0, len(inorder) - 1)

